body:
生成代码时，如果数据表中存在一个名为'action'的字段时，在生成代码后操作列不显示，
操作列 actionColumn.key 'action'和表中 action字段冲突，版本 `VersionApp = "2.18.9"`。

生成示例代码如下：

表格列 columns 中的 action 字段：
```typescript
// 表格列
 export const columns = [
{
     title: 'action',
     // key: 'action', // 和操作action冲突
     align: 'left',
     width: -1,
   },
]
```

操作列中的 key 也是 'action'
```typescript
const actionColumn = reactive({
     width: 144,
     title: '操作',
     key: 'action',
     fixed: 'right',
     render(record: State) {
       return h(TableAction as any, {
         style: 'button',
         actions: [
           {
             label: '编辑',
             onClick: handleEdit.bind(null, record),
             auth: ['/config/edit'],
           },

           {
             label: '删除',
             onClick: handleDelete.bind(null, record),
             auth: ['/config/delete'],
           },
         ],

       });
     },
   });

```

